func setPrimDoc(vmInst *vm.VM, className, selector string, classSide bool, doc string) {
	cls := vmInst.Classes.Lookup(className)
	if cls == nil {
		return
	}
	selID := vmInst.Selectors.Lookup(selector)
	if selID < 0 {
		return
	}
	vt := cls.VTable
	if classSide {
		vt = cls.ClassVTable
	}
	m := vt.Lookup(selID)
	if m == nil {
		return
	}
	if ds, ok := m.(vm.DocStringable); ok && ds.DocString() == "" {
		ds.SetDocString(doc)
	}
}
